class TableExpr<F extends PgRow<F>> {
  TableExpr(TableFields<F> tableFields) : _tableFields = tableFields;

  TableExpr.internal() : _tableFields = null;

  final TableFields<F>? _tableFields;

  TableFields<F> get $tableFields {
    final tf = _tableFields;
    if (tf == null) {
      throw StateError(
        "TableExpr.\$tableFields: this TableExpr was produced by FK navigation "
        "and does not carry a TableFields. The target table's fields cannot "
        "be exposed from an auto-joined expression.",
      );
    }
    return tf;
  }

  ScalarExpression<T> $asExpr<T extends Object>(String fieldName) =>
      ($tableFields.$byName(fieldName) as Field<T>).$asExpression;

  TableExprFk<Next, NextPk>
  $asFk<Next extends PgRow<Next>, NextPk extends Object>(String fieldName) {
    final field = $tableFields.$byName(fieldName);
    final fk = field.referencedFk;
    if (fk == null) {
      throw StateError(
        "TableExpr.\$asFk: column \"$fieldName\" of "
        "${$tableFields.$tableId.qualified} is not a single-column FK.",
      );
    }
    return TableExprFk<Next, NextPk>(
      parentPath: JoinPath.root(),
      parentForeignKeys: const [],
      fkField: field as Field<NextPk>,
      fk: fk,
    );
  }
}

class TableExprFk<Target extends PgRow<Target>, PkType extends Object>
    extends ScalarExpression<PkType> {
  TableExprFk({
    required JoinPath parentPath,
    required List<ForeignKey> parentForeignKeys,
    required Field<PkType> fkField,
    required ForeignKey fk,
  }) : _parentPath = parentPath,
       _parentForeignKeys = parentForeignKeys,
       _fkField = fkField,
       _fk = fk;

  final JoinPath _parentPath;
  final List<ForeignKey> _parentForeignKeys;
  final Field<PkType> _fkField;
  final ForeignKey _fk;

  @override
  PgTypeAdapter<PkType> get $pgType => _fkField.pgType;

  @override
  String get $placeholderHint => _fkField.name;

  @override
  String $renderSql(QueryParams params) =>
      _fkField.$asExpression.$renderSql(params);

  TableExpr<Target> get $target {
    final extendedPath = _parentPath.append(_fkField.tableId, _fkField.name);
    final extendedFks = [..._parentForeignKeys, _fk];
    return JoinedTableExpr<Target>(
      path: extendedPath,
      foreignKeys: extendedFks,
      targetTableId: _fk.referencedTable,
    );
  }
}

class JoinedTableExpr<Target extends PgRow<Target>> extends TableExpr<Target> {
  JoinedTableExpr({
    required JoinPath path,
    required List<ForeignKey> foreignKeys,
    required TableId targetTableId,
  }) : _path = path,
       _foreignKeys = foreignKeys,
       _targetTableId = targetTableId,
       super.internal();

  final JoinPath _path;
  final List<ForeignKey> _foreignKeys;
  final TableId _targetTableId;

  JoinPath get $joinPath => _path;
  List<ForeignKey> get $foreignKeyChain => _foreignKeys;
  TableId get $targetTableId => _targetTableId;

  @override
  ScalarExpression<T> $asExpr<T extends Object>(String fieldName) {
    final targetMetadata = TableMetadata.lookup(_targetTableId);
    final field = targetMetadata.$fields.$byName(fieldName);
    return _JoinedFieldExpr<T>(
      path: _path,
      foreignKeys: _foreignKeys,
      fieldName: fieldName,
      pgType: field.pgType as PgTypeAdapter<T>,
    );
  }

  @override
  TableExprFk<Next, NextPk>
  $asFk<Next extends PgRow<Next>, NextPk extends Object>(String fieldName) {
    final targetMetadata = TableMetadata.lookup(_targetTableId);
    final field = targetMetadata.$fields.$byName(fieldName);
    final fk = field.referencedFk;
    if (fk == null) {
      throw StateError(
        "JoinedTableExpr.\$asFk: column \"$fieldName\" of "
        "${_targetTableId.qualified} is not a single-column FK.",
      );
    }
    return TableExprFk<Next, NextPk>(
      parentPath: _path,
      parentForeignKeys: _foreignKeys,
      fkField: field as Field<NextPk>,
      fk: fk,
    );
  }
}

class _JoinedFieldExpr<T extends Object> extends ScalarExpression<T> {
  _JoinedFieldExpr({
    required this.path,
    required this.foreignKeys,
    required this.fieldName,
    required this.pgType,
  });

  final JoinPath path;
  final List<ForeignKey> foreignKeys;
  final String fieldName;
  final PgTypeAdapter<T> pgType;

  @override
  PgTypeAdapter<T> get $pgType => pgType;

  @override
  String get $placeholderHint => fieldName;

  @override
  String $renderSql(QueryParams params) {
    final alias = _resolveJoinChain(params.scope);
    final col = quoteIdent(fieldName);
    return "$alias.$col";
  }

  String _resolveJoinChain(QueryScope scope) {
    var prefix = JoinPath.root();
    String? alias;
    for (var i = 0; i < path.segments.length; i++) {
      final segment = path.segments[i];
      prefix = prefix.append(segment.source, segment.fkColumn);
      alias = scope.$resolveJoin(prefix, foreignKeys[i]);
    }
    return alias!;
  }
}

