typedef ManualJoin = ({TableExpr target, JoinKind kind, Predicate on});

class Select<F extends PgRow<F>> {
  Select._(this.source);

  factory Select.from(TableExpr<F> root) => Select._(root);

  final TableExpr<F> source;
  final List<ManualJoin> _manualJoins = [];

  Predicate Function()? _where;
  List<Expression> Function()? _projection;
  List<Expression> Function()? _groupBy;
  Predicate Function()? _having;
  Expectation? _expectation;

  Subquery get $base => _asBase();

  /// Adds a join and returns a [TableExpr<U>] wrapping the joined
  /// [TableFields<U>], ready to be referenced in subsequent callbacks.
  ///
  /// [outer] (`false` by default) switches between `INNER` and `LEFT`;
  /// [kind] allows forcing a variant (`full`).
  TableExpr<U> join<U extends PgRow<U>>(
    TableExpr<U> other, {
    required Predicate Function(TableExpr<U> handle) on,
    bool outer = false,
    JoinKind? kind,
  }) {
    _manualJoins.add((
      target: other,
      kind: kind ?? (outer ? JoinKind.left : JoinKind.inner),
      on: on(other),
    ));
    return other;
  }

  Select<F> where(Predicate Function() builder) {
    _where = builder;
    return this;
  }

  Select<F> project(List<Expression> Function() builder) {
    _projection = builder;
    return this;
  }

  Select<F> groupBy(List<Expression> Function() builder) {
    _groupBy = builder;
    return this;
  }

  Select<F> having(Predicate Function() builder) {
    _having = builder;
    return this;
  }

  Select<F> expecting({
    List<OrderTerm> orderBy = const [],
    int? limit,
    int? offset,
  }) {
    _expectation = Expectation(orderBy: orderBy, limit: limit, offset: offset);
    return this;
  }

  Predicate $exists() => SubQueryPredicates.$exists(_asBase());

  Predicate $notExists() => SubQueryPredicates.$notExists(_asBase());

  /// Fixes the projection to a singleton and exposes this `Select` as a
  /// scalar expression usable in a projection or a comparison of the
  /// outer `Select`. Equivalent to
  /// `(SELECT <expr> FROM ... WHERE ...)`. The `Select` must not have
  /// been configured with `project(...)` beforehand; after `valueList`,
  /// using it as a `SelectBase` (`exists`, `inSubquery`, `run`) will
  /// produce the scalar projection.
  Expression<U> valueList<U extends Object>(Expression<U> Function() builder) {
    final expr = builder();
    _projection = () => [expr];
    return _ScalarSubquery<U>(_asBase(), expr.$pgType);
  }

  Future<SelectResult> run(PgConn conn, {bool needTotalRowCount = false}) =>
      _runQuery(conn, _asBase(), needTotalRowCount: needTotalRowCount);

  SelectQuery _asBase() => SelectQuery._(
    source: source.$tableFields,
    manualJoins: List.unmodifiable(_manualJoins),
    where: _where?.call(),
    projection: _projection?.call() ?? const [],
    groupBy: _groupBy?.call() ?? const [],
    having: _having?.call(),
    expectation: _expectation,
  );
}

